class Solution:
    def findSubarrays(self, nums):
        sums = [nums[i] + nums[i + 1] for i in range(len(nums) - 1)]
        for i in range(len(sums)):
            for j in range(i + 1, len(sums)):
                if sums[i] == sums[j]:
                    return True
        return False

