var findSubarrays = function(nums) {
    const seen = new Set();
    for (let i = 0; i < nums.length - 1; i++) {
        const s = nums[i] + nums[i + 1];
        if (seen.has(s)) return true;
        seen.add(s);
    }
    return false;
};
